CREATE TABLE estado (
    codigo BIGINT PRIMARY KEY,
    nome VARCHAR(50) NOT NULL,
    sigla VARCHAR(2) NOT NULL
);

CREATE SEQUENCE sequence_estado INCREMENT 1 START 1 MINVALUE 1 MAXVALUE 9223372036854775807 CACHE 1;

CREATE TABLE cidade (
    codigo BIGINT PRIMARY KEY,
    nome VARCHAR(50) NOT NULL,
    codigo_estado BIGINT NOT NULL,
    FOREIGN KEY (codigo_estado) REFERENCES estado(codigo)
);

CREATE SEQUENCE sequence_cidade INCREMENT 1 START 1 MINVALUE 1 MAXVALUE 9223372036854775807 CACHE 1;






